module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);
// Define internal wires for generate and propagate signals
wire [32:1] g;
wire [32:1] p;
wire [32:1] c;
// Generate and propagate signals for each bit position
genvar i;
generate
    for (i = 1; i <= 32; i = i+1) begin : gen
        assign g[i] = A[i] & B[i];
        assign p[i] = A[i] | B[i];
    end
endgenerate
// Ripple carry adder using generate and propagate signals
always @(*) begin
    // Initialize carry to 0
    c[0] = 0;
    // Calculate carry-out for each bit position
    for (i = 1; i <= 32; i = i+1) begin : carry_gen
        assign c[i] = g[i-1] | (p[i-1] & c[i-1]);
    end
    // Calculate sum for each bit position
    for (i = 1; i <= 32; i = i+1) begin : sum_gen
        assign S[i] = p[i] ^ c[i-1];
    end
    // Set carry-out to last carry
    assign C32 = c[32];
end
endmodule
